const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const KIEAI_API_KEY = '706600fe6244dedaa3c72b71ffe52e97';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
if (!recipient_email) {
  try {
    const rows = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value&user_id=eq.${encodeURIComponent(userId)}`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    for (const row of rows) {
      if (row.key === 'recipient_email') recipient_email = row.value;
      if (row.key === 'bcc_email') bcc_email = row.value;
    }
  } catch (e) {
    recipient_email = 'eric@agileadtesting.com';
    bcc_email = '';
  }
}

const genre = trigger.genre_slug || 'post-apocalyptic';
const guidelines = {
  'post-apocalyptic': 'Muted earth tones, atmospheric haze, dramatic lighting. Overgrown ruins, crumbling infrastructure, vast empty landscapes. Mood: haunting beauty in decay. Style: cinematic concept art, digital matte painting.',
  'political-scifi': 'Dark imposing structures, dramatic chiaroscuro lighting. Vast space stations, parliamentary chambers, propaganda aesthetics. Mood: cerebral tension. Style: retro-futurism meets brutalist architecture.',
  'historical-time-travel': 'Rich period-accurate details, warm golden-hour lighting. Layered timelines shown through visual juxtaposition. Mood: nostalgic wonder. Style: romantic realism with subtle anachronisms.',
  'ai-marketing': 'Clean minimalist tech aesthetic, gradient blues and purples. Circuit patterns, neural network visualizations, data streams. Mood: innovative and forward-looking. Style: modern digital art, sleek corporate futurism.',
  'political-history': 'Documentary-style gravitas, amber and sepia tones. Architecture of power, crowds, pivotal moments. Mood: weight of history. Style: oil painting meets photojournalism.',
  'ancient-history': 'Classical painting style, warm golden light, rich earth tones with lapis lazuli and gold accents. Marble, stone, papyrus textures. Mood: reverent immersion. Style: neoclassical oil painting, museum-quality detail.',
  'metaphysical-romance': 'Ethereal soft light, dreamlike atmosphere, warm pastels with deep jewel tones. Mist, glowing auras, intertwined silhouettes. Mood: transcendent longing and soul-deep connection. Style: surrealist romanticism, luminous digital painting.'
};
const art_guidelines = guidelines[genre] || guidelines['post-apocalyptic'];

return [{ json: { art_guidelines, recipient_email, bcc_email: bcc_email || '', KIEAI_API_KEY, SUPABASE_URL, SUPABASE_API_KEY } }];

const trigger = $('workflow_trigger').first().json;
const settings = $('settings').first().json;
const description = trigger.image_description || '';
const title = trigger.story_title || '';
const genre = trigger.genre_slug || '';
const contentType = trigger.content_type || 'Chapter';
const artGuidelines = settings.art_guidelines || '';

const synopsisMatch = description.match(/Chapter synopsis:\s*(.*?)(?:\n\nOpening|$)/s);
const excerptMatch = description.match(/Opening scene excerpt:\s*(.*?)(?:\n\nCreate|$)/s);
const synopsis = synopsisMatch ? synopsisMatch[1].trim() : '';
const excerpt = excerptMatch ? excerptMatch[1].trim().substring(0, 800) : '';

const prompt = `A photorealistic editorial photograph for ${contentType} of "${title}".

Scene: ${synopsis ? synopsis : description}

Visual Reference from Text:
${excerpt ? excerpt.substring(0, 600) : 'Use the scene description above for visual composition.'}

Lighting: Motivated naturalistic lighting appropriate to the scene setting. Use contrasting light sources to create visual tension - warm vs cool, natural vs artificial. No shadows hiding faces. Dramatic but realistic.

Composition: Low camera angle, wide-to-medium shot, subject slightly off-center. Shallow depth of field (f/2.8 equivalent), sharp on primary subject, environment receding into bokeh. 16:9 cinematic crop, book-cover-ready composition with negative space in upper third for title treatment.

Photographic style: Documentary portraiture meets editorial magazine photography. Shot on full-frame sensor, 35mm equivalent lens. Color grade: desaturated midtones with preserved warm skin tones, atmospheric tones in background. High detail on fabric texture, skin, and environmental elements. Mood: atmospheric tension, historical weight, intimate human drama. Professional editorial photography, award-winning photojournalism quality.

Do NOT include any text, words, titles, watermarks, or logos in the image.

${artGuidelines ? 'Additional guidelines: ' + artGuidelines : ''} --ar 16:9 --stylize 850 --v 7`;

return [{ json: { prompt, title, genre } }];

// Insert generated_images_v2 record (storage upload handled by upload_to_storage HTTP Request node)
const SUPABASE_URL = $('settings').first().json.SUPABASE_URL;
const SUPABASE_API_KEY = $('settings').first().json.SUPABASE_API_KEY;
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';
const title = trigger.story_title || 'untitled';
const genre = trigger.genre_slug || '';
const contentType = trigger.content_type || 'cover_art';
const projectId = trigger.project_id || null;
const prompt = $('build_prompt').first().json.prompt || '';

// Extract storage path from the upload response (Key field from Supabase Storage API)
// The upload_to_storage HTTP Request node returns {Key: 'cover-images/+14105914612/...'}
const uploadResult = $input.first().json;
let storagePath = '';
if (uploadResult && uploadResult.Key) {
  // Key is 'cover-images/+14105914612/filename.png' - strip bucket prefix
  storagePath = uploadResult.Key.replace(/^cover-images\//, '');
} else {
  // Fallback: compute path
  const slug = title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 60);
  const ts = new Date().toISOString().replace(/[-:T]/g, '').substring(0, 14);
  storagePath = `${userId}/${ts}_${slug}.png`;
}

// Determine image_type from content_type
let imageType = 'cover_art';
if (contentType.toLowerCase().includes('chapter')) imageType = 'chapter_art';
if (contentType.toLowerCase().includes('social')) imageType = 'social_media';
if (contentType.toLowerCase().includes('newsletter')) imageType = 'newsletter_section';

// Insert record into generated_images_v2
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/generated_images_v2`,
    headers: {
      'apikey': SUPABASE_API_KEY,
      'Authorization': `Bearer ${SUPABASE_API_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: {
      user_id: userId,
      project_id: projectId,
      image_type: imageType,
      storage_path: storagePath,
      original_prompt: prompt.substring(0, 10000),
      genre_slug: genre || null,
      image_format: 'png',
      generation_model: 'nano-banana-pro',
      metadata: { story_title: title, content_type: contentType }
    }
  });
} catch (e) {
  console.log('DB insert failed:', e.message);
}

// Pass through all data + storage_path for downstream nodes
// HOTFIX 2026-04-18: reference binary from download_image (not $input, which is upload_to_storage's JSON-only response)
return [{ json: { storage_path: storagePath, ...trigger }, binary: $('download_image').first().binary }];
